// ---- Pillar 1: Site Audit — Google PageSpeed Insights → Supabase ----
// Free. No key needed for low-volume. Checks performance, SEO, accessibility.
// Stores snapshot in content_pipeline table (status=audit) for history tracking.
// Architecture: sequential desktop+mobile → Supabase upsert → summary return.
const ENV = (typeof $env !== 'undefined' && $env) ? $env : process.env;
const TARGET_URL = 'https://markexis.com';
const PSI_BASE = 'https://www.googleapis.com/pagespeedonline/v5/runPagespeed';
// Key optional — falls back to keyless (lower rate limit, same data)
const KEY_PARAM = ENV.GOOGLE_PLACES_API_KEY ? `&key=${ENV.GOOGLE_PLACES_API_KEY}` : '';

async function runAudit(strategy) {
  const url = `${PSI_BASE}?url=${encodeURIComponent(TARGET_URL)}&strategy=${strategy}&category=performance&category=seo&category=accessibility&category=best-practices${KEY_PARAM}`;
  try {
    const res = await this.helpers.httpRequest({ method: 'GET', url, json: true, timeout: 60000 });
    const cats = res.lighthouseResult?.categories || {};
    const audits = res.lighthouseResult?.audits || {};
    return {
      strategy,
      performance: Math.round((cats.performance?.score || 0) * 100),
      seo:         Math.round((cats.seo?.score || 0) * 100),
      accessibility: Math.round((cats.accessibility?.score || 0) * 100),
      best_practices: Math.round((cats['best-practices']?.score || 0) * 100),
      lcp:  audits['largest-contentful-paint']?.displayValue || null,
      fid:  audits['total-blocking-time']?.displayValue || null,
      cls:  audits['cumulative-layout-shift']?.displayValue || null,
      fcp:  audits['first-contentful-paint']?.displayValue || null,
      ttfb: audits['server-response-time']?.displayValue || null,
      ok: true
    };
  } catch (e) {
    return { strategy, ok: false, error: e.message.slice(0, 200) };
  }
}

// Run desktop and mobile sequentially (PSI rate-limits parallel calls)
const desktop = await runAudit.call(this, 'desktop');
await new Promise(r => setTimeout(r, 3000));
const mobile  = await runAudit.call(this, 'mobile');

const now = new Date().toISOString();
const auditRecord = {
  keyword: `site_audit_${now.slice(0,10)}`,
  topic: `Site Audit — markexis.com — ${now.slice(0,10)}`,
  status: 'audit',
  pillar: 'ops',
  article_draft: JSON.stringify({ desktop, mobile, url: TARGET_URL, audited_at: now }, null, 2),
  updated_at: now
};

if (ENV.SUPABASE_URL) {
  await this.helpers.httpRequest({
    method: 'POST',
    url: `${ENV.SUPABASE_URL}/rest/v1/content_pipeline?on_conflict=keyword`,
    headers: {
      apikey: ENV.SUPABASE_ANON_KEY, Authorization: `Bearer ${ENV.SUPABASE_ANON_KEY}`,
      'Content-Type': 'application/json', Prefer: 'resolution=merge-duplicates'
    },
    body: JSON.stringify(auditRecord),
    json: false, timeout: 20000
  }).catch(e => console.error('Supabase write failed:', e.message));
}

// Alert thresholds — log warning if below target
const alerts = [];
if (desktop.ok && desktop.performance < 70) alerts.push(`Desktop performance: ${desktop.performance}/100 (< 70)`);
if (desktop.ok && desktop.seo < 85) alerts.push(`Desktop SEO: ${desktop.seo}/100 (< 85)`);
if (mobile.ok && mobile.performance < 50) alerts.push(`Mobile performance: ${mobile.performance}/100 (< 50)`);

return [{ json: { ok: true, desktop, mobile, alerts, auditedAt: now } }];
